def get_cosine_similarity(vec1, vec2):
    dot_product = np.dot(vec1,vec2)
    norm_vec1 = np.linalg.norm(vec1)
    norm_vec2 = np.linalg.norm(vec2)
    if norm_vec1 == 0 or norm_vec2 == 0 :
        return 0.0
    return dot_product/(norm_vec1*norm_vec2)

def has_code_signature(text: str) -> bool:
    code_patterns = [
        r"(def\s+\w+\(|function\s+\w+\(|const\s+\w+\s*=)",  # Functions
        r"(import\s+\w+|from\s+\w+\s+import)",              # Imports
        r"(class\s+\w+:|class\s+\w+\s+extends)",            # Classes
        r"(<\/?[a-z][^>]*>|\{\s*.*\s*\})",                  # HTML tags / JSobjects
        r"(for\s+.+\s+in|while\s+\(.+\))"                   # Contrstructures
    ]
    for pattern in code_patterns:
        if re.search(pattern, text):
            return True 
    return False

def classify_prompt(text: str)-> str:
    clean_text = text.strip()  # remove whitespace character 
    word_count = len(clean_text.split())   #split into word 

    #basic conversation 
    trivial_words = {"hi", "hello", "hey", "bye", "goodbye", "thanks", "thank you"}
    if word_count <= 3 and any(word in clean_text.lower() for word in trivial_words):
        return "20b"

    # high complexity already known 
    if has_code_signature(clean_text):
        return "gemini"
  
    complex_word = {"debug", "reseach", "refactor", "api setup"}
    for kw in complex_word:
        if kw in clean_text.lower():
            return "gemini"
  
    #else case 
    try:
        api_key = os.getenv("HUGGINGFACEHUB_API_TOKEN")
        if not api_key:
            print("⚠️ ERROR: HUGGINGFACEHUB_API_TOKEN is missing from environment variables!")
            return "120b"

        api_url = "https://api-inference.huggingface.co/pipeline/feature-extraction/sentence-transformers/all-MiniLM-L6-v2"
        headers = {"Authorization": f"Bearer {api_key}"}
      
        # FIX 1: Increased timeout to 35 to allow the free-tier model time to wake up
        response = requests.post(
            api_url, 
            headers=headers, 
            json={"inputs": clean_text, "options": {"wait_for_model": True}},
            timeout=35
        )
        response.raise_for_status()
        data = response.json()
      
        # FIX 2: Safely extract the vector whether Hugging Face returns 1D or 2D lists
        if isinstance(data, list) and len(data) > 0 and isinstance(data[0], list):
            query_vector = np.array(data[0])
        else:
            query_vector = np.array(data)
          
    except requests.exceptions.Timeout:
        print("⚠️ Hugging Face API timed out while waking up.")
        return "120b"
    except Exception as e:
        print(f"⚠️ Embedding API failed: {e}")
        return "120b"
      
    scores = {}
    
    # CRITICAL FIX: Changed CENTROIDS (which was undefined) to COMPLEXITY_ANCHORS
    for tier, centroid in COMPLEXITY_ANCHORS.items():
        similarity_score = get_cosine_similarity(query_vector, centroid)
        scores[tier] = similarity_score
    
    best_tier = ""
    highest_score = -1.0
    
    for tier, score in scores.items():
        if score > highest_score:
            highest_score = score
            best_tier = tier
            
    print(f"DEBUGGING SCORES: {scores}") 
    print(f"DEBUGGING BEST TIER: {best_tier}")
    
    # Override complexity
    if best_tier == "27b" and highest_score < 0.40 and word_count > 40:
        return "120b"
    
    if best_tier == "120b" and word_count > 120:
        return "gemini"
        
    return best_tier
